import * as React from "react";
import AppContext from "./context";
import DataPickerPopup from "./components/DataPickerPopup";
import {Navigate, Route, Routes, useLocation, useParams} from "react-router-dom";
import PartnerBrands from "./PartnerBrands";
import BrandBookingList from "./routes/BrandBookingList";
import BookingDetails from "./routes/BookingDetails";
import BookingExternalDetails from "./routes/BookingExternalDetails";
import axios from "axios";
import {initialUrl} from "./ConfigApp";

function BookingsToBookingL() {
    let {bookingCode} = useParams();
    let location = useLocation();

    if (!bookingCode) {
        return <Navigate to="/booking" state={{from: location}} replace/>;
    }

    return (<Navigate
        to={`/booking/l/${bookingCode}`}
        state={{from: location}}
        replace
    />);
}

const App = ({appProps: {secureParams, partnerId, apiKey, userName}}) => {
    const [selectBrand, setSelectBrand] = React.useState({});
    const [selectBooking, setSelectBooking] = React.useState(null);

    const [brandId, setBrandId] = React.useState([]);

    const [bookingId, setBookingId] = React.useState(null);
    const [bookingType, setBookingType] = React.useState(null);
    const [bookingInfo, setBookingInfo] = React.useState({});

    const [clientIsNotComeState, setClientIsNotComeState] = React.useState(false);
    const [clientIsNotComeData, setClientIsNotComeData] = React.useState({});
    const [clientIsComeState, setClientIsComeState] = React.useState(false);
    const [clientIsComeData, setClientIsComeData] = React.useState({});

    const [allBookingsGroupSort, setAllBookingsGroupSort] = React.useState([]);

    const datePickerDataInitialState = {
        isShow: false,
        currentIndex: 0,
        maxIndex: 2,
        loaderIndex: 1,
        successIndex: 2,
        errorIndex: 3,
    }

    const [datePickerData, setDatePickerData] = React.useState(datePickerDataInitialState)
    const datePickerDataUtils = {
        onOpen: (value = 0) => {
            return setDatePickerData({...datePickerData, isShow: true, currentIndex: value})
        },
        onClose: () => {
            return setDatePickerData({...datePickerData, isShow: false})
        },
        onNext: () => {
            if (datePickerData.currentIndex >= datePickerData.maxIndex) return
            return setDatePickerData({...datePickerData, currentIndex: datePickerData.currentIndex + 1})
        },
        onError: () => {
            return setDatePickerData({...datePickerData, isShow: true, currentIndex: datePickerData.errorIndex})
        },
        onSuccess: () => {
            return setDatePickerData({...datePickerData, isShow: true, currentIndex: datePickerData.successIndex})
        },
        setCurrentIndex: (value) => {
            if (value >= datePickerData.maxIndex) return
            return setDatePickerData({...datePickerData, currentIndex: value})
        }
    }

    const onDateConfirmation = async ({booking_id, booking_datetime}) => {
        try {
            datePickerDataUtils.onOpen(datePickerData.loaderIndex)
            const dateProps = {
                booking_id: booking_id,
                booking_datetime: booking_datetime,
                apiKey: apiKey,
                userName: userName
            }
            // console.log(dateProps)
            const axYos = await axios.post(initialUrl + "/webhook/partner_lk/set_booking_datetime/", dateProps)
            // console.log("axYos", axYos)
            return datePickerDataUtils.onSuccess()
        } catch (e) {
            console.error(e)
            return datePickerDataUtils.onError()
        }
    }

    return (<AppContext.Provider
        value={{
            datePickerData,
            setDatePickerData,
            selectBrand,
            setSelectBrand,
            clientIsNotComeState,
            setClientIsNotComeState,
            clientIsNotComeData,
            setClientIsNotComeData,
            clientIsComeState,
            setClientIsComeState,
            clientIsComeData,
            setClientIsComeData,
            selectBooking,
            setSelectBooking,
            bookingId,
            setBookingId,
            bookingType,
            setBookingType,
            bookingInfo,
            setBookingInfo,
            allBookingsGroupSort,
            setAllBookingsGroupSort,
            brandId,
            setBrandId, // apiKey, userName,
            secureParams,
            onDateConfirmation,
            datePickerDataUtils
        }}
    >

        <DataPickerPopup datePickerData={datePickerData} datePickerDataUtils={datePickerDataUtils}/>
        <Routes>
            {/* Выбор бренда для показа бронирований на него  */}
            <Route
                path="/booking/"
                element={<PartnerBrands partnerIdParams={partnerId}/>}
            />

            {/* Список бронирования для выбранного бренда */}
            <Route
                path="/booking/:brandId"
                element={<BrandBookingList partnerIdParams={partnerId}/>}
            />

            {/* Страница брони */}
            <Route
                path="/booking/l/:bookingCode"
                element={<BookingDetails partnerIdParams={partnerId}/>}
            />

            {/* Страница внешней брони */}
            <Route
                path="/booking/e/:bookingExternalCode"
                element={<BookingExternalDetails partnerIdParams={partnerId}/>}
            />

            {/* URL оставлен для совместимости, чтобы прежние ссылки работали */}
            <Route path="/bookings/:bookingCode" element={<BookingsToBookingL/>}/>
        </Routes>
    </AppContext.Provider>);
}

export default App