import React from "react";
import { Button, Paper, Stack, Typography } from "@mui/material";
import dayjs from "dayjs";
import "dayjs/locale/ru";
import AppContext from "../context";
import BookingCardHeader from "./BookingCardHeader";

dayjs.locale("ru");

export default function BookingCard({ booking }) {
    const {
        setClientIsNotComeState,
        setClientIsNotComeData,
        setClientIsComeState,
        setClientIsComeData,
        setSelectBooking,
        setBookingId,
        setBookingType,
        bookingInfo,
        setBookingInfo,
        selectBrand,
        onDateConfirmation,
        datePickerDataUtils,
        brandId,
        setBrandId,
    } = React.useContext(AppContext);

    return (
        <Paper
            id={`code-${booking.code}`}
            key={booking.code}
            variant="outlined"
            sx={{ padding: "1rem 0.5rem" }}
        >
            <Stack spacing={2}>
                <BookingCardHeader booking={booking} />
                <Stack>
                    <Typography sx={{ fontWeight: 500 }}>Услуга</Typography>
                    <Typography>
                        {booking.order_item_service_program.service_program.service_type}
                    </Typography>
                    <Typography>
                        {booking.order_item_service_program.service_program.name}
                        {booking.order_item_service_program.service_program
                            .program_duration_to_hours_minutes &&
                            ", " +
                            booking.order_item_service_program.service_program
                                .program_duration_to_hours_minutes}
                    </Typography>
                    {booking.order_item_service_program.order_item_service_program_variants.map(
                        (variant, index) => {
                            return (
                                <Typography key={index}>
                                    {variant.qty}шт - {variant.name}
                                    {variant.duration_to_hours_minutes &&
                                        ", " + variant.duration_to_hours_minutes}
                                </Typography>
                            );
                        }
                    )}
                </Stack>
                <Stack>
                    <Typography>
                        📅
                        {dayjs(booking.booking_date_tz).format("DD.MM.YYYY")} 🕘
                        {dayjs(booking.booking_date_tz).format("HH:mm")}
                    </Typography>
                    <Typography>
                        😉{booking.visitor_name} ☎ {booking.visitor_phone}
                    </Typography>
                </Stack>
                <Stack>
                    <Typography>
                        Стоимость:{" "}
                        {
                            booking.order_item_service_program
                                .partner_price_all_variant_sum_per_date_order
                        }{" "}
                        ₽
                    </Typography>
                    <Typography>
                        Совершена предоплата: {Number(booking.pre_pay_amount)} ₽
                    </Typography>
                    <Typography>
                        Доплата на месте: {Number(booking.post_pay_amount)} ₽
                    </Typography>
                </Stack>
                <Typography>Адрес: {booking.address.address}</Typography>
                {!booking.visitor_not_come_bool &&
                    !booking.visitor_come_bool &&
                    !booking.status.includes("book") ? (
                    <Stack direction="row" columnGap={1}>
                        <Button
                            sx={{ width: "100%" }}
                            variant="outlined"
                            color="error"
                            onClick={() => {
                                setSelectBooking(booking);
                                setBookingId(booking.id);
                                setBookingType(booking.booking_type);
                                setBookingInfo({
                                    ...bookingInfo,
                                    pre_pay_amount: booking.pre_pay_amount,
                                    booking_type: "booking",
                                });
                                setClientIsNotComeData({ state: booking.state });
                                setClientIsNotComeState(true);

                            }}
                        >
                            Клиент не пришёл
                        </Button>
                        {selectBrand.partner_settings?.payment_when_visitor_come &&
                            !booking.visitor_come_bool && (
                                <Button
                                    sx={{ width: "100%" }}
                                    variant="outlined"
                                    color="success"
                                    onClick={() => {
                                        setSelectBooking(booking);
                                        setBookingId(booking.id);
                                        setBookingType(booking.booking_type);
                                        setBookingInfo({
                                            ...bookingInfo,
                                            pre_pay_amount: booking.pre_pay_amount,
                                            booking_type: booking.booking_type,
                                            code: booking.code,
                                            visitor_name: booking.visitor_name,
                                            visitor_phone: booking.visitor_phone,
                                        });
                                        // console.log(booking);
                                        setClientIsComeData({ state: booking.state });
                                        setClientIsComeState(true);
                                    }}
                                >
                                    Клиент пришёл
                                </Button>
                            )}
                    </Stack>
                ) : !booking.state.includes("new") &&
                <>{booking.desired_times_tz_list.map((dateTime, i) => <Button key={i}
                    sx={{ width: "100%" }}
                    variant="outlined"
                    color="info"
                    onClick={async () => {
                        const dateTimeFormated = dayjs(dateTime).format(`DD.MM.YYYY HH:mm:00`)
                        await onDateConfirmation({
                            booking_id: booking.id,
                            booking_datetime: dateTimeFormated
                        })
                    }}

                >
                    Подтверждаю {dayjs(dateTime).format("DD.MM.YYYY")} в {dayjs(dateTime).format("dddd")} на {dayjs(dateTime).format("HH:mm")}
                </Button>)}<Button
                    sx={{ width: "100%" }}
                    variant="outlined"
                    color="info"
                    onClick={() => {
                        setSelectBooking(booking)
                        datePickerDataUtils.onOpen()
                    }}
                >

                        Согласовать другое время
                    </Button></>
                }
            </Stack>
        </Paper>
    );
}
