import {Typography} from "@mui/material";
import React, {memo} from "react";

const BookingCardHeader = memo(({booking, type = "booking"}) => {
    let bookingStateSwitch
    // console.log(`booking.code: ${booking.code};`, `booking.status: ${booking.status};`, `booking.state: ${booking.state};`, `booking.visitor_name: ${booking.visitor_name};`, `booking.visitor_phone: ${booking.visitor_phone};`, `booking.pre_pay_amount: ${booking.pre_pay_amount};`)
    // console.log(`booking.desired_times_tz_list: `, booking.desired_times_tz_list)

    switch (booking?.status) {
        case "new":
            bookingStateSwitch = "ждёт подтверждения"
            break
        case "booked":
            bookingStateSwitch = "бронь согласована"
            break
        case "booked_from_cancelled":
            bookingStateSwitch = "бронь согласована"
            break
        case "cancelled":
            bookingStateSwitch = "бронь отменена"
            break
        case "pre_cancel_refund_client":
            bookingStateSwitch = "бронь отменена клиентом, деньги возвращены клиенту"
            break
        case "pre_approve_time":
            bookingStateSwitch = "время предварительного утверждения"
            break
        case "cancelled_to_rebook":
            bookingStateSwitch = "отменено для перебронирования"
            break
        case "pre_cancel_client":
            bookingStateSwitch = "бронь отменена клиентом"
            break
        case "pre_cancel_move_client":
            bookingStateSwitch = "бронь отменена, клиент перенёс бронирование"
            break
        default:
            bookingStateSwitch = ""
            break
    }

    if (type === "booking") {
        return <div>
            <Typography>
                {booking.visitor_not_come_bool
                    ? "🟠"
                    : booking.state.includes("new") ? booking.status.includes("book") ? "🟢" : "🔵"
                        : booking.state.includes("book")
                            ? "🟢"
                            : booking.state.includes("cancel")
                                ? "🔴" : "⚪"}
                БРОНИРОВАНИЕ № {booking.code}
            </Typography>
            <Typography>
                Статус:{" "}
                {bookingStateSwitch}
                {booking.visitor_not_come_bool && ", клиент не пришёл"}
            </Typography>
        </div>
    }
    if (type === "booking_external") {
        return <div>
            <Typography>
                {booking.visitor_not_come_bool ? "🟠" : ""}
                БРОНИРОВАНИЕ № {booking.external_code}
            </Typography>
        </div>
    }
})

export default BookingCardHeader