export function priceCalculate(bookingExternal) {
  if (bookingExternal) {
    if (bookingExternal.booking_external_correct) {
      return bookingExternal.booking_external_correct.price_partner;
    } else if (bookingExternal.price_partner_per_order) {
      return bookingExternal.price_partner_per_order;
    } else return bookingExternal.price_on_site_per_order;
  }
}

export function postPayAmountCalculate(bookingExternal) {
  if (bookingExternal) {
    if (bookingExternal.booking_external_correct) {
      return bookingExternal.booking_external_correct.post_pay_amount;
    } else return bookingExternal.post_pay_amount;
  }
}
export function prePayAmountCalculate(bookingExternal) {
  if (bookingExternal) {
    if (bookingExternal.booking_external_correct) {
      return bookingExternal.booking_external_correct.pre_pay_amount;
    } else return bookingExternal.pre_pay_amount;
  }
}
