import dayjs from "dayjs";
import "dayjs/locale/ru";

export default function Utils() {
  dayjs.locale("ru");

  const isYesterday = require("dayjs/plugin/isYesterday");

  dayjs.extend(isYesterday);
  return {
    groupBy: function (key) {
      // console.log('groupBy')
      return function group(array) {
        // console.log('group')
        return array.reduce((acc, obj) => {
          // console.log('reduce', acc, obj)
          const property = obj[key];
          acc[property] = acc[property] || [];
          acc[property].push(obj);
          return acc;
        }, {});
      };
    },
    objSortDesk: function (obj) {
      const keys = Object.keys(obj).reverse();
      const newObj = new Object();
      for (let key of keys) {
        // console.log(key)
        newObj[key] = obj[key];
      }

      return newObj;
    },
    sortByKey: function (array, key) {
      // Сортирует массив по указанному ключу по возрастанию
      return array.sort((a, b) => {
        let x = a[key];
        let y = b[key];

        return x < y ? -1 : x > y ? 1 : 0;
      });
    },
    dateFormater(date) {
      // console.log("dateFormater(date)", date);
      let currentDate = new Date();
  
      if (
        dayjs(date).format("DD.MM.YYYY") ===
        dayjs(currentDate).format("DD.MM.YYYY")
      ) {
        return <span style={{ color: "rgb(25, 118, 210)" }}>Сегодня</span>;
      } else if (dayjs(date).add(-1, "day").isYesterday()) {
        return "Вчера";
      }
  
      return dayjs(date).format("DD.MM.YYYY, dddd");
    },
  };
}
