import * as React from "react";
// import { useContext } from "react";
import axios from "axios";
import {Alert, Snackbar, Typography} from "@mui/material";
import {Container, Stack} from "@mui/system";
// import dayjs from "dayjs";
import {useNavigate, useParams} from "react-router-dom";
import Loader from "../components/Loader";
import ClientIsNotCome from "../ClientIsNotCome";
import ClientIsCome from "../ClientIsCome";
import {baseURL} from "../ConfigApp";
import Utils from "../components/Utils";
// import "dayjs/locale/ru";
import AppContext from "../context";
import BookingList from "../components/BookingList";

import checkBrandAccess from "../utils/checkBrandAccess"
import AccessDenied from "../components/AccessDenied";
import ErrorPage from "../error-page";
// import CheckBrandAccess from "../utils/checkBrandAccess";

axios.defaults.baseURL = baseURL;

// dayjs.locale("ru");

// const isYesterday = require("dayjs/plugin/isYesterday");

// dayjs.extend(isYesterday);

// Функция очистки массива от "пустышек"

export default function BrandBookingList({partnerIdParams}) {
    const [postResponseBookingNulls, setPostResponseBookingNulls] =
        React.useState([]);
    const [
        postResponseBookingExternalNulls,
        setPostResponseBookingExternalNulls,
    ] = React.useState([]);
    const [postResponseBooking, setPostResponseBooking] = React.useState([]);
    const [postResponseBookingExternal, setPostResponseBookingExternal] =
        React.useState([]);
    const [isLoading, setIsLoading] = React.useState(true);
    const [isError, setIsError] = React.useState(false)
    const [snackbar, setSnackbar] = React.useState(null);
    const [bookingsLimit, setBookingsLimit] = React.useState(25);
    const [bookingsOffset, setBookingsOffset] = React.useState(0);
    const [bookingsOffsetExternal, setBookingsOffsetExternal] = React.useState(0);
    const [totalCountBookings, setTotalCountBookings] = React.useState(0);
    const [totalCountBookingsExternal, setTotalCountBookingsExternal] =
        React.useState(0);
    const [nextPage, setNextPage] = React.useState(true);
    const [checkBrand, setCheckBrand] = React.useState(null);  // Разрешён ли доступ к инфе?
    const {selectBrand, setSelectBrand} = React.useContext(AppContext);
    const navigation = useNavigate();
    const handleCloseSnackbar = () => setSnackbar(null);

    const {
        clientIsNotComeState, setClientIsNotComeState,
        clientIsNotComeData, setClientIsNotComeData,
        clientIsComeState, setClientIsComeState,
        clientIsComeData, setClientIsComeData,
        selectBooking, setSelectBooking,
        bookingId, setBookingId,
        bookingType, setBookingType,
        bookingInfo, setBookingInfo,
        allBookingsGroupSort, setAllBookingsGroupSort,
        setBrandId,
        // apiKey,
        // userName,
        secureParams
    } = React.useContext(AppContext);

    let offsetUrl = "";
    let {brandId} = useParams();

    React.useEffect(() => {
        // В момент открытия страницы
        // Проверим, есть ли у данного партнёра указанный бренд

        checkBrandAccess(partnerIdParams, brandId, secureParams)
            .then(res => setCheckBrand(res))

    }, [partnerIdParams, brandId]);


    const handleProcessRowUpdateError = React.useCallback((error) => {
        setSnackbar({children: error.message, severity: "error"});
    }, []);


    const getBrandFromServer = async (brandId) => {
        await axios({
            url: `${baseURL}/brand/${brandId}?${secureParams}`,
            method: "GET",
            responseType: "json",
        })
            .then((response) => {
                const brand = response.data;
                // const meta = data.meta;
                // const brand = data.object;
                // console.log("data", data);
                // console.log("brand", brand);
                setSelectBrand(brand);
                setIsLoading(false);
            })
            .catch(function (error) {
                console.error(error);
                setIsError(true)
                // Если ошибка, то показать ошибку и предложить нажать ещё раз
            });
    };

    async function getBookingsDataFromServer(url = "", toTarget = "") {
        if (!brandId) {
            return;
        }

        if (toTarget === "booking") {
            await axios({
                url: url,
                method: "GET",
                responseType: "json",
            })
                .then((response) => {
                    const data = response.data.objects;
                    // console.log(data);
                    const meta = response.data.meta;
                    if (meta.next) {
                        setNextPage(true);
                    } else setNextPage(false);
                    setTotalCountBookings(meta.total_count);
                    setPostResponseBookingNulls((prevBookings) => {
                        return [
                            ...prevBookings,
                            ...data.map((booking) => {
                                if (
                                    booking.status === "booked" ||
                                    booking.status === "cancelled"
                                ) {
                                    if (booking.booking_date) {
                                        if (booking.booking_external) {
                                            return {...booking, booking_type: "booking_and_booking_external"};
                                        } else {
                                            return {...booking, booking_type: "booking"};
                                        }
                                    }
                                }
                                return;
                            }),
                        ];
                    });

                    setPostResponseBooking((prevBookings) => {
                        return [
                            ...prevBookings,
                            ...undefindArrayCleanHandle(
                                data.map((booking) => {
                                    if (
                                        booking.status === "booked" ||
                                        booking.status === "cancelled"
                                    ) {
                                        if (booking.booking_date) {
                                            if (booking.booking_external) {
                                                return {...booking, booking_type: "booking_and_booking_external"};
                                            } else {
                                                return {...booking, booking_type: "booking"};
                                            }
                                        }
                                    }
                                    return;
                                })
                            ),
                        ];
                    });
                })
                .catch(function (error) {
                    console.log(error);
                    handleProcessRowUpdateError(new Error(error));
                    // Если ошибка, то показать ошибку и предложить нажать ещё раз
                });
        }
        if (toTarget === "booking_external") {
            await axios({
                url: url,
                method: "GET",
                responseType: "json",
            })
                .then((response) => {
                    const data = response.data.objects;
                    const meta = response.data.meta;

                    // console.log(data);

                    if (meta.next) {
                        setNextPage(true);
                    } else setNextPage(false);
                    setTotalCountBookingsExternal(meta.total_count);
                    setPostResponseBookingExternalNulls((prevBookings) => {
                        return [...prevBookings, ...data];
                    });
                    setPostResponseBookingExternal((prevBookingsExternal) => {
                        return [
                            ...prevBookingsExternal,
                            ...undefindArrayCleanHandle(
                                data.map((booking) => {
                                    return {...booking, booking_type: "booking_external"};
                                })
                            ),
                        ];
                    });
                })
                .catch(function (error) {
                    console.log(error);
                    handleProcessRowUpdateError(new Error(error));
                    // Если ошибка, то показать ошибку и предложить нажать ещё раз
                });
        }
    }

    const undefindArrayCleanHandle = (array) => {
        return array.filter(Boolean); // [1, 2]
    };


    React.useEffect(() => {
        if (postResponseBooking || postResponseBookingExternal) {
            const bookingAndBookingExternalArray = [
                ...postResponseBooking,
                ...postResponseBookingExternal,
            ];

            // console.log("bookingAndBookingExternalArray", bookingAndBookingExternalArray);
            // // Группируем массив операций по дате создания
            const groupByBookingDateTzWoTime = Utils().groupBy(
                "booking_date_tz_wo_time"
            );
            // console.log("groupByBookingDateTzWoTime", groupByBookingDateTzWoTime);
            const bookingAndBookingExternalGroup = groupByBookingDateTzWoTime(
                bookingAndBookingExternalArray
            );
            // console.log("bookingAndBookingExternalGroup", bookingAndBookingExternalGroup);
            // // Отстортируем полученный группированный массив по убыванию
            const bookingAndBookingExternalGroupSort = Utils().sortByKey(
                Object.entries(bookingAndBookingExternalGroup),
                0
            );
            // console.log("accountOperationsGroupSort", bookingAndBookingExternalGroupSort);
            // Отсортированный по возрастанию массив перевернём, чтобы получился по убыванию
            setAllBookingsGroupSort(bookingAndBookingExternalGroupSort.reverse());

            if (selectBooking) {
                // if(selectBooking.visitor_not_come_bool){}
                // console.log("selectBooking", selectBooking);
                if (selectBooking.visitor_not_come_bool) {
                    setAllBookingsGroupSort(
                        bookingAndBookingExternalGroupSort.map((day) => {
                            return [
                                day[0],
                                day[1].map((booking) => {
                                    if (booking.link_code === selectBooking.link_code) {
                                        return {
                                            ...booking,
                                            visitor_not_come_bool: true,
                                        };
                                    } else return booking;
                                }),
                            ];
                        })
                    );
                }
                if (selectBooking.visitor_come_bool) {
                    setAllBookingsGroupSort(
                        bookingAndBookingExternalGroupSort.map((day) => {
                            return [
                                day[0],
                                day[1].map((booking) => {
                                    if (booking.link_code === selectBooking.link_code) {
                                        return {
                                            ...booking,
                                            visitor_come_bool: true,
                                        };
                                    } else return booking;
                                }),
                            ];
                        })
                    );
                }
            }
        }
    }, [postResponseBooking, postResponseBookingExternal, selectBooking]);
    // React.useEffect(() => {}, [selectBooking]);
    const getNextPageInfo = async (url = "") => {
        if (bookingsOffset <= totalCountBookings) {
            if (nextPage) {
                setBookingsOffset(bookingsOffset + 25);
                getBookingsDataFromServer(url, "booking");
            }
        } else if (bookingsOffsetExternal <= totalCountBookingsExternal) {
            if (
                (postResponseBookingNulls !== 0,
                totalCountBookings !== 0,
                postResponseBookingNulls.length >= totalCountBookings)
            ) {
                if (nextPage) {
                    setBookingsOffsetExternal(bookingsOffsetExternal + 25);
                    getBookingsDataFromServer(url, "booking_external");
                }
            }
        }
        return;
    };

    React.useEffect(() => {
        // Скрол до операции в списке, которую только что закрыли
        const scrollToHashElement = () => {
            const {hash} = window.location;
            const elementToScroll = document.getElementById(hash?.replace("#", ""));

            if (!elementToScroll) return;

            window.scrollTo({
                top: elementToScroll.offsetTop - 120,
                // top: elementToScroll.offsetTop - offset,
                behavior: "smooth",
            });
        };

        // if (!trigger) return;

        scrollToHashElement();
        window.addEventListener("hashchange", scrollToHashElement);
        return window.removeEventListener("hashchange", scrollToHashElement);
    }, [postResponseBookingNulls, clientIsComeState, clientIsNotComeState]);

    React.useEffect(() => {
        // Получим объект бренда
        getBrandFromServer(brandId);
        setBrandId(brandId);
    }, [brandId]);

    React.useEffect(() => {
        offsetUrl = ''

        if (
            (bookingsOffset > 0,
            totalCountBookings > 0,
            bookingsOffset > totalCountBookings)
        ) {
            offsetUrl = `${baseURL}/booking_external/?brand=${brandId}&limit=${bookingsLimit}&offset=${bookingsOffsetExternal}`;
            // getNextPageInfo(offsetUrl);
        } else {
            offsetUrl = `${baseURL}/booking/?address__brand=${brandId}&limit=${bookingsLimit}&offset=${bookingsOffset}`;
        }

        offsetUrl += secureParams
        getNextPageInfo(offsetUrl);

        // if (
        //   postResponseBooking.length > 0 ||
        //   postResponseBookingExternal.length > 0
        // ) {
        //   setIsLoading(false);
        // }
    }, [
        bookingsOffset,
        totalCountBookings,
        bookingsOffsetExternal,
        totalCountBookingsExternal,
    ]);

    React.useEffect(() => {
        // покажем список броней, если есть данные в массиве броней
        if (allBookingsGroupSort.length > 0) {
            setIsLoading(false);
        }
    }, [allBookingsGroupSort]);

    return (
        <>
            {isLoading && checkBrand === null ? (
                <Loader/>
            ) : isError ? <ErrorPage/> : checkBrand == false ? <AccessDenied/>
                : clientIsNotComeState ? (
                    // Экран "Клиент не пришёл"
                    <ClientIsNotCome
                        clientIsNotComeState={clientIsNotComeState}
                        setClientIsNotComeState={setClientIsNotComeState}
                        clientIsNotComeData={clientIsNotComeData}
                    />
                ) : clientIsComeState ? (
                    // Экран "Клиент пришёл"
                    <ClientIsCome
                        bookingType={bookingType}
                        bookingId={bookingId}
                        clientIsComeState={clientIsComeState}
                        setClientIsComeState={setClientIsComeState}
                        bookingInfo={bookingInfo}
                        clientIsComeData={clientIsComeData}
                    />
                ) : checkBrand ?
                    // Экран "Список бронирований"
                    <Container
                        maxWidth="sm"
                        style={{marginTop: "1rem", marginBottom: "1rem"}}
                    >
                        <Stack spacing={4} sx={{marginTop: "1.5rem"}}>
                            <Stack spacing={2}>
                                <div
                                    style={{
                                        display: "flex",
                                        alignItems: "center",
                                        marginBottom: "1rem",
                                    }}
                                >
                                    <Typography
                                        style={{
                                            display: "block",
                                            margin: "0 auto",
                                            textAlign: "center",
                                            alignItems: "center",
                                        }}
                                        sx={{
                                            textAlign: "center",
                                            fontWeight: 600,
                                            marginBottom: "2rem",
                                        }}
                                        variant="h5"
                                    >
                                        Список бронирований
                                    </Typography>
                                    {
                                        //                <CloseIcon
                                        //                  fontSize="large"
                                        //                  sx={{ cursor: "pointer" }}
                                        //                  onClick={() =>
                                        //                    navigation(
                                        //                      "/brands?partnerId=" + selectBrand.partner_settings?.id
                                        //                    )
                                        //                  }
                                        //                />
                                    }
                                </div>
                                <Typography
                                    style={{
                                        display: "block",
                                    }}
                                    sx={{
                                        fontWeight: 500,
                                    }}
                                    variant="h6"
                                >
                                    {postResponseBookingNulls.length < totalCountBookings &&
                                        `${postResponseBookingNulls.length} / ${totalCountBookings}`}
                                    {postResponseBookingExternalNulls.length !==
                                        totalCountBookingsExternal &&
                                        `${postResponseBookingExternalNulls.length} / ${totalCountBookingsExternal}`}
                                </Typography>
                                <Stack spacing={6}>
                                    {/* Тут будет allBookingsGroupSort */}
                                    {allBookingsGroupSort &&
                                        allBookingsGroupSort.map((booking, index) => {
                                            return (
                                                // Выводим брони, группированные по датам
                                                <Stack key={booking[0]} spacing={1}>
                                                    <Typography
                                                        sx={{
                                                            position: "sticky",
                                                            height: "fit-content",
                                                            top: "50",
                                                            backgroundColor: "#fff",
                                                            p: "1rem 0",
                                                            zIndex: 2,
                                                        }}
                                                        variant="h5"
                                                    >
                                                        {Utils().dateFormater(booking[0])}
                                                    </Typography>
                                                    {/* <div>BookingList</div> */}
                                                    <BookingList bookings={booking[1]}/>
                                                </Stack>
                                            );
                                        })}
                                </Stack>
                            </Stack>
                        </Stack>

                        {!!snackbar && (
                            <Snackbar
                                open
                                anchorOrigin={{vertical: "bottom", horizontal: "center"}}
                                onClose={handleCloseSnackbar}
                                autoHideDuration={6000}
                            >
                                <Alert {...snackbar} onClose={handleCloseSnackbar}/>
                            </Snackbar>
                        )}
                    </Container>
                    : (
                        <></>
                    )}
        </>
    );
}
