export default async function checkBrandAccess(partnerId, brandId, secureParams){
        const brandsData = await getBrandsForPartnerFromServer(partnerId, secureParams)
        // console.log('brandsData', brandsData);

        const brandsIds = brandsData.map((brand)=>brand.id)
        // console.log('brandsIds.includes(brandId)', brandsIds.includes(Number(brandId)))
        // console.log(brandsIds)
        // console.log(brandId)

    return brandsIds.includes(Number(brandId))

}