import * as React from "react";
import ReactDOM from "react-dom/client";
import {BrowserRouter,} from "react-router-dom";
// import Booking from "./routes/BookingDetails";
// import Bookings from "./routes/BookingList";
import "./reset.css";
import "./index.css";
import App from "./App";
import dayjs from "dayjs";
import axios from "axios";
import {initialUrl} from "./ConfigApp";
import {dataPickerPopupUtils} from "./components/DataPickerPopup";
// import './index.css';
// import App from './App';
// import reportWebVitals from './reportWebVitals';

const cur = document.currentScript;
const cur_src = cur.src;
const url = new URL(cur_src);
let partnerId = url.searchParams.get("partnerId");
let apiKey = url.searchParams.get("apiKey");
let userName = url.searchParams.get("userName");
let secureParams = '';

// console.log('apiKey', apiKey);

if (apiKey && userName) {
    userName = encodeURIComponent(userName);

    // secureParams подставляется в каждом URL'е, чтобы у партнёра был доступ к данным
    secureParams = `&api_key=${apiKey}&username=${userName}`
}

// Заглушка для тестирования на локальном
if (!partnerId) {
    // partnerId = 1111;
    partnerId = 1051;
    apiKey = '78332c31eb43263355c570eda1dca9e60732a3e4';
    userName = '%2B79234216672';
    secureParams = `&api_key=${apiKey}&username=${userName}`
}

const appProps = {
    secureParams,
    partnerId,
    apiKey,
    userName
}

dayjs.locale("ru");


ReactDOM.createRoot(document.getElementById("root")).render(<React.StrictMode>
    <BrowserRouter>
        {/* <RouterProvider router={router} /> */}
        <App appProps={appProps}/>
    </BrowserRouter>
</React.StrictMode>);
