import {Done} from "@mui/icons-material";
import {Button} from "@mui/material";

const DatePickerSuccess = ({datePickerDataUtils}) => {
    return (<div style={{
        display: "flex",
        justifyContent: "center",
        alignItems: 'center',
        maxWidth: "12em",
        maxHeight: "100%",
        width: "calc(100% - 1rem)",
        height: "12em",
        borderRadius: "0.5rem",
        background: "#fff",

    }}>
        <div
            style={{display: "flex", flexDirection: "column", alignItems: "center"}}>
            <Done
                style={{marginBottom: "1rem"}} color="success" sx={{fontSize: "3.5rem"}}/><p
            style={{fontSize: "1.1rem"}}>Успешно</p><Button variant="contained" sx={{marginTop: "1rem"}} color="secondary"
                                                          onClick={() => datePickerDataUtils.onClose()}>Закрыть</Button>
        </div>
    </div>)
}
export default DatePickerSuccess