import * as React from "react";
import axios from "axios";
import { Alert, Button, Snackbar, TextField, Typography } from "@mui/material";
import { LocalizationProvider } from "@mui/x-date-pickers/LocalizationProvider";
import { AdapterDayjs } from "@mui/x-date-pickers/AdapterDayjs";
import { Container, Stack } from "@mui/system";
import CloseIcon from "@mui/icons-material/Close";

import Loader from "./components/Loader";

import { baseURL } from "./ConfigApp";
import { MobileDatePicker } from "@mui/x-date-pickers";
import dayjs from "dayjs";
import AppContext from "./context";
import { useNavigate } from "react-router-dom";

axios.defaults.baseURL = baseURL;

export default function ClientIsCome({
  // bookingType,
  // bookingId,
  // bookingInfo,
  clientIsComeData,
  setClientIsComeState,
}) {
  const [isLoading, setIsLoading] = React.useState(true);

  const {
    selectBrand,
    setSelectBrand,
    selectBooking,
    setSelectBooking,
    bookingInfo,
    bookingType,
    bookingId,
    brandId,
    allBookingsGroupSort,
    setAllBookingsGroupSort,
    secureParams,
  } = React.useContext(AppContext);

  React.useEffect(() => {
    setIsLoading(false);
  }, []);

  const [value, setValue] = React.useState(
    dayjs(new Date()).format(`YYYY-MM-DD`)
  );

  const handleChange = (newValue) => {
    setValue(dayjs(newValue).format(`YYYY-MM-DD`));
  };
  const [snackbar, setSnackbar] = React.useState(null);

  const handleCloseSnackbar = () => setSnackbar(null);

  const handleProcessRowUpdateError = React.useCallback((error) => {
    setSnackbar({ children: error.message, severity: "error" });
  }, []);

  // console.log("bookingsDrawerInfo", bookingsDrawerInfo);

  const navigate = useNavigate();

  function postClientIsComeResponse(postResponseData) {
    console.log('postClientIsComeResponse', postClientIsComeResponse);
    if (bookingType === "booking") {
      axios
        .post(`${baseURL}/visitor_come/?${secureParams}`, {
          brand: `/brand/${brandId}/`,
          booking: `/booking/${postResponseData.bookingId}/`,
          date_visitor_come: postResponseData.date,
          source_action: 'PARTNER_LK',
          who_action: 'PARTNER',
        })
        .then(function (response) {
          console.log(response);
          setSelectBooking({ ...selectBooking, visitor_come_bool: true });
          setAllBookingsGroupSort(
            allBookingsGroupSort.map((day) => {
              return [
                day[0],
                day[1].map((booking) => {
                  if (booking.link_code === selectBooking.link_code) {
                    return { ...booking, visitor_come_bool: true };
                  } else return booking;
                }),
              ];
            })
          );
          console.log(3);
          navigate(`/booking/${brandId}#code-${selectBooking.code}`);
          setClientIsComeState(false);
          setSnackbar({
            children: "Данные успешно изменены",
            severity: "success",
          });
        })
        .catch(function (error) {
          console.log(error);
          handleProcessRowUpdateError(new Error(error));
          // Если ошибка, то показать ошибку и предложить нажать ещё раз
        });
    } else if (bookingType === "booking_external") {
      axios
        .post(`${baseURL}/visitor_come/?${secureParams}`, {
          brand: `/brand/${brandId}/`,
          booking_external: `/booking_extenal/${postResponseData.bookingId}/`,
          date_visitor_come: postResponseData.date,
          source_action: 'PARTNER_LK',
          who_action: 'PARTNER',
        })
        .then(function (response) {
          console.log(response);
          setSelectBooking({ ...selectBooking, visitor_come_bool: true });
          setAllBookingsGroupSort(
            allBookingsGroupSort.map((day) => {
              return [
                day[0],
                day[1].map((booking) => {
                  if (booking.link_code === selectBooking.link_code) {
                    return { ...booking, visitor_come_bool: true };
                  } else return booking;
                }),
              ];
            })
          );
          console.log(3);
          navigate(`/booking/${brandId}#ecode-${selectBooking.external_code}`);
          setClientIsComeState(false);
          setSnackbar({
            children: "Данные успешно изменены",
            severity: "success",
          });
        })
        .catch(function (error) {
          console.log(error);
          handleProcessRowUpdateError(new Error(error));
          // Если ошибка, то показать ошибку и предложить нажать ещё раз
        });
    }
  }

  return (
    <>
      {isLoading ? (
        <Loader />
      ) : (
        <Container
          maxWidth="sm"
          style={{ marginTop: "1rem", marginBottom: "1rem" }}
        >
          <Stack spacing={4} sx={{ marginTop: "1.5rem" }}>
            <Stack>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  marginBottom: "1rem",
                }}
              >
                <Typography
                  style={{
                    display: "block",
                    margin: "0 auto",
                    textAlign: "center",
                    alignItems: "center",
                  }}
                  sx={{
                    textAlign: "center",
                    fontWeight: 600,
                    marginBottom: "2rem",
                  }}
                  variant="h5"
                >
                  Клиент пришёл
                </Typography>
                <CloseIcon
                  fontSize="large"
                  sx={{ cursor: "pointer" }}
                  onClick={() => setClientIsComeState(false)}
                />
              </div>
              <Stack spacing={2}>
                <Stack spacing={0.5}>
                  <Typography variant="h6">
                    Бронирование: № {bookingInfo.code}
                  </Typography>
                  <Typography variant="body1">
                    Клиент: {bookingInfo.visitor_phone}{" "}
                    {bookingInfo.visitor_name}
                  </Typography>
                </Stack>
                <Stack spacing={0.5}>
                  <Typography variant="h6">Дата оказания услуги</Typography>
                  <LocalizationProvider dateAdapter={AdapterDayjs}>
                    <MobileDatePicker
                      inputFormat="DD.MM.YYYY"
                      value={value}
                      onChange={handleChange}
                      renderInput={(params) => <TextField {...params} />}
                    />
                  </LocalizationProvider>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
          <Button
            sx={{
              display: "block",
              marginTop: "1rem",
              marginLeft: "auto",
            }}
            variant="contained"
            size="large"
            onClick={async () => {
              await postClientIsComeResponse({
                // ...bookingsDrawerInfo,
                bookingType: bookingType,
                bookingId: bookingId,
                date: value,
              });
            }}
          >
            Сохранить
          </Button>
          {!!snackbar && (
            <Snackbar
              open
              anchorOrigin={{ vertical: "bottom", horizontal: "center" }}
              onClose={handleCloseSnackbar}
              autoHideDuration={6000}
            >
              <Alert {...snackbar} onClose={handleCloseSnackbar} />
            </Snackbar>
          )}
        </Container>
      )}
    </>
  );
}
