import {CircularProgress} from "@mui/material";

const DatePickerLoader = () => {
    return <div style={{
        display: "flex",
        justifyContent: "center",
        alignItems: 'center',
        maxWidth: "12em",
        maxHeight: "100%",
        width: "calc(100% - 1rem)",
        height: "12em",
        borderRadius: "0.5rem",
        background: "#fff",

    }}>
        <div
            style={{display: "flex", flexDirection: "column", alignItems: "center"}}>
            <CircularProgress
                style={{marginBottom: "1rem"}} color="secondary"/><p>Идёт загрузка...</p></div>
    </div>
}
export default DatePickerLoader