import axios from "axios";
import React, { useEffect, useState } from "react";
import { Link, useNavigate, useParams } from "react-router-dom";
import { baseURL } from "../ConfigApp";
import dayjs from "dayjs";
import "dayjs/locale/ru";
import { Button, Paper, Typography } from "@mui/material";
import { Stack } from "@mui/system";
import {
  postPayAmountCalculate,
  prePayAmountCalculate,
  priceCalculate,
} from "../utils/bookingExternal?";
import AppContext from "../context";
import ClientIsNotCome from "../ClientIsNotCome";
import ClientIsCome from "../ClientIsCome";
import Loader from "../components/Loader";
import BookingExternalCard from "../components/BookingExternalCard";
import AccessDenied from "../components/AccessDenied";
import checkBrandAccess from "../utils/checkBrandAccess";

dayjs.locale("ru");

axios.defaults.baseURL = baseURL;

async function getBrandsForPartnerFromServer(partnerId, secureParams) {
  const url = `${baseURL}/brand/?partner_settings__id=${partnerId}${secureParams}`;
  const response = await axios.get(url);
  return response.data;
}

async function getBookingExternalDataFromServer(bookingExternalCode, secureParams) {
  // Запросим с сервера информацию по брони
  if (!bookingExternalCode) {
    return null;
  }

  return await axios({
    url: `${baseURL}/booking_external/?external_code=${bookingExternalCode}${secureParams}`,
    method: "GET",
    responseType: "json",
  })
    .then((response) => {
      const objects = response.data.objects;

      if (objects) {
        console.log("objects[0]", objects[0]);
        return objects[0];
      }
    })
    .catch(function (error) {
      console.log(error);
      // handleProcessRowUpdateError(new Error(error));
      // Если ошибка, то показать ошибку и предложить нажать ещё раз
    });
}

export default function BookingExternalDetails({ partnerIdParams }) {
  const [brands, setBrands] = useState([]);
  const [bookingExternal, setBookingExternal] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [checkBrand, setCheckBrand] = React.useState(null);  // Разрешён ли доступ к инфе?

  const {
    clientIsComeState,
    clientIsNotComeState,
    clientIsComeData,
    clientIsNotComeData,
    setClientIsNotComeState,
    setClientIsNotComeData,
    setClientIsComeState,
    setClientIsComeData,
    setSelectBooking,
    setBookingId,
    setBookingType,
    bookingInfo,
    setBookingInfo,
    selectBrand,
    bookingType,
    bookingId,
    brandId,
    setBrandId,
    secureParams
  } = React.useContext(AppContext);

  const navigation = useNavigate();
  let { bookingExternalCode } = useParams();

  var partnerId = partnerIdParams;

  useEffect(() => {
    // В момент открытия страницы
    // Запросим список брендов у партнёра
    const brandsData = getBrandsForPartnerFromServer(partnerId, secureParams)
      .then((data) => data.objects)
      .then((brands) => setBrands(brands));
    console.log(brandsData);
  }, [partnerId]);

  useEffect(() => {
    // В момент открытия страницы
    // Запросим информацию о брони
    getBookingExternalDataFromServer(bookingExternalCode, secureParams)
    .then((bookingExt) => {
      if (!bookingExt){
        // Если не пришёл объект брони, то считаем, что доступ запрещён
        setIsLoading(false);
        setCheckBrand(false)
        return
      }

      const brandUrl = bookingExt.brand;
      // console.log(brandUrl);
      const brand_id = brandUrl.replace("/api/autorpp/brand/", "").replace("/", "");
      setSelectBooking({ ...bookingExt, booking_type: "booking_external" });
      // console.log("data", data);
      // console.log(bookingExt);
      setBookingExternal({ ...bookingExt, booking_type: "booking_external" });
      setBrandId(brand_id);
      // console.log(brand_id);
      setIsLoading(false);
    });

    // console.log("bookingExt", bookingExt);
  }, [bookingExternalCode]);
  // console.log("bookingExternal", bookingExternal);

  React.useEffect(() => {
    // В момент открытия страницы
    // Проверим, есть ли у данного партнёра указанный бренд

    if (Number(brandId)) {
    checkBrandAccess(partnerIdParams, brandId, secureParams)
      .then(res => setCheckBrand(res))
    }
  }, [partnerIdParams, brandId]);


  return (
    <>
      {isLoading ? (
        <Loader />
      ) 
      : checkBrand==false ? <AccessDenied /> 
      : (
        <>
          {bookingExternal && clientIsNotComeState ? (
            // Экран "Клиент не пришёл"
            <ClientIsNotCome
              // bookingId={bookingId}
              clientIsNotComeState={clientIsNotComeState}
              setClientIsNotComeState={setClientIsNotComeState}
              clientIsNotComeData={clientIsNotComeData}
              // bookingType={bookingType}
              // selectBooking={selectBooking}
            />
          ) 
          : bookingExternal && clientIsComeState ? ( // Экран "Клиент пришёл"
            <ClientIsCome
              bookingType={bookingType}
              bookingId={bookingId}
              clientIsComeState={clientIsComeState}
              setClientIsComeState={setClientIsComeState}
              bookingInfo={bookingInfo}
              clientIsComeData={clientIsComeData}
            />
          ) 
          : bookingExternal && checkBrand ? 
          <>
            {brandId && (
              <Link
                to={`/booking/${brandId}#ecode-${bookingExternal.external_code}`}
                style={{ color: "initial", textDecoration: "none" }}
                // key={index}
              >
                <Button>Все брони</Button>
              </Link>
            )}          

            <BookingExternalCard bookingExternal={bookingExternal} />
            </>
          :(
              <></>
          )}
        </>
      )}
    </>
  );
}
