import React from "react";
import { Button, Paper, Stack, Typography } from "@mui/material";
import dayjs from "dayjs";
import "dayjs/locale/ru";

import {
  postPayAmountCalculate,
  prePayAmountCalculate,
  priceCalculate,
} from "../utils/bookingExternal?";
import AppContext from "../context";
import BookingCardHeader from "./BookingCardHeader";

dayjs.locale("ru");

export default function BookingExternalCard({ bookingExternal }) {
  const {
    setClientIsNotComeState,
    setClientIsNotComeData,
    setClientIsComeState,
    setClientIsComeData,
    setSelectBooking,
    setBookingId,
    setBookingType,
    bookingInfo,
    setBookingInfo,
    selectBrand,
    setIsDataPickerShow,
  } = React.useContext(AppContext);
  return (
    <Paper
      id={`ecode-${bookingExternal.external_code}`}
      key={bookingExternal.external_code}
      variant="outlined"
      sx={{ padding: "1rem 0.5rem" }}
    >
      <Stack spacing={2}>
        <BookingCardHeader booking={bookingExternal} type="booking_external"/>
        <Stack>
          <Typography sx={{ fontWeight: 500 }}>Услуга</Typography>
          <Typography
            dangerouslySetInnerHTML={{
              __html: bookingExternal.service_name,
            }}
          ></Typography>
        </Stack>
        <Stack>
          <Typography>
            📅
            {dayjs(bookingExternal.booking_date).format("DD.MM.YYYY")} 🕘
            {dayjs(bookingExternal.booking_date).format("HH:mm")}
          </Typography>
          <Typography>
            😉{bookingExternal.visitor_name} ☎ {bookingExternal.visitor_phone}
          </Typography>
        </Stack>
        <Stack>
          <Typography>
            Стоимость: {Number(priceCalculate(bookingExternal))} ₽
          </Typography>
          <Typography>
            Совершена предоплата:{" "}
            {Number(prePayAmountCalculate(bookingExternal))} ₽
          </Typography>
          <Typography>
            Доплата на месте: {Number(postPayAmountCalculate(bookingExternal))}{" "}
            ₽
          </Typography>
        </Stack>
        <Typography>Адрес: {bookingExternal.address_name}</Typography>

        {
          // Спрячем все кнопки, если есть отметка, что "клиент не пришёл" или "клиент пришёл"
          !bookingExternal.visitor_not_come_bool &&
            !bookingExternal.visitor_come_bool && (
              <Stack direction="row" columnGap={1}>
                <Button
                  sx={{ width: "100%" }}
                  variant="outlined"
                  color="error"
                  onClick={() => {
                    setSelectBooking(bookingExternal);
                    setBookingId(bookingExternal.id);
                    setBookingType(bookingExternal.booking_type);
                    setBookingInfo({
                      ...bookingInfo,
                      pre_pay_amount: prePayAmountCalculate(bookingExternal),
                      booking_type: bookingExternal.booking_type,
                      code: bookingExternal.external_code,
                      visitor_name: bookingExternal.visitor_name,
                      visitor_phone: bookingExternal.visitor_phone,
                    });
                    setClientIsNotComeData({ state: bookingExternal.state });
                    setClientIsNotComeState(true);
                  }}
                >
                  Клиент не пришёл
                </Button>

                {selectBrand.partner_settings?.payment_when_visitor_come &&
                  !bookingExternal.visitor_come_bool && (
                    <Button
                      sx={{ width: "100%" }}
                      variant="outlined"
                      color="success"
                      onClick={() => {
                        setSelectBooking(bookingExternal);
                        setBookingId(bookingExternal.id);
                        setBookingType(bookingExternal.booking_type);
                        setBookingInfo({
                          ...bookingInfo,
                          pre_pay_amount:
                            prePayAmountCalculate(bookingExternal),
                          booking_type: bookingExternal.booking_type,
                          code: bookingExternal.code,
                          visitor_name: bookingExternal.visitor_name,
                          visitor_phone: bookingExternal.visitor_phone,
                        });
                        setClientIsComeData({ state: bookingExternal.state });
                        setClientIsComeState(true);
                      }}
                    >
                      Клиент пришёл
                    </Button>
                  )}
              </Stack>
            )
        }
      </Stack>
    </Paper>
  );
}
