import React from "react";
import { Box, Typography } from "@mui/material";

export default function AccessDenied() {
  return (
    <Box
      sx={{
        position: "absolute",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        top: "40%",
        left: "50%",
        right: "50%",
        transform: "translateY(-50%)",
        gap: "1rem",
      }}
    >
      <Typography width="max-content" variant="subtitle">
        Доступ запрещён
      </Typography>
    </Box>
  );
}
