import {Stack} from "@mui/material";
import {lazy, useEffect, useState} from "react";


const BookingCard = lazy(() => import('./BookingCard'))
const BookingExternalCard = lazy(() => import('./BookingExternalCard'))
const BookingWBookingExternalCard = lazy(() => import('./BookingWBookingExternalCard'))



const BookingList = ({bookings}) => {
    if (!bookings) return
    const [allBookings, setAllBookings] = useState([])
    useEffect(() => {
        setAllBookings(bookings)
    }, [])

    return (
        <Stack spacing={2}>
            {allBookings.map((booking, index) => {
                if (booking.booking_type === "booking") {
                    return <BookingCard key={index} booking={booking}/>;
                } else if (booking.booking_type === "booking_and_booking_external") {
                    return <BookingWBookingExternalCard key={index} booking={booking}/>;
                } else if (booking.booking_type === "booking_external") {
                    return <BookingExternalCard key={index} bookingExternal={booking}/>;
                }
                return;
            })}
        </Stack>
    );
}



export default BookingList
