import axios from "axios";
import React, {useEffect, useState} from "react";
import {Link, useNavigate, useParams} from "react-router-dom";
import {baseURL} from "../ConfigApp";
import dayjs from "dayjs";
import "dayjs/locale/ru";
import AppContext from "../context";
import ClientIsNotCome from "../ClientIsNotCome";
import ClientIsCome from "../ClientIsCome";
import Loader from "../components/Loader";
import BookingCard from "../components/BookingCard";
import checkBrandAccess from "../utils/checkBrandAccess";
import AccessDenied from "../components/AccessDenied";
import BookingWBookingExternalCard from "../components/BookingWBookingExternalCard";
import {Container} from "@mui/system";

dayjs.locale("ru");

axios.defaults.baseURL = baseURL;

