async function getBookingDataFromServer(bookingCode, secureParams) {
    // Запросим с сервера информацию по брони
    if (!bookingCode) {
        return null;
    }

    return await axios({
        url: `${baseURL}/booking/?code=${bookingCode}${secureParams}`,
        method: "GET",
        responseType: "json",
    })
        .then((response) => {
            const objects = response.data.objects;
            if (objects && objects.length) {
                return objects[0];
            }
            return null
        })
        .catch(function (error) {
            console.log(error);
            //   handleProcessRowUpdateError(new Error(error));
            // Если ошибка, то показать ошибку и предложить нажать ещё раз
        });
}

export default function BookingDetails({partnerIdParams}) {
    const [booking, setBooking] = useState({});
    const [isLoading, setIsLoading] = useState(true);
    const [checkBrand, setCheckBrand] = React.useState(null); // Разрешён ли доступ к инфе?

    const {
        brandId,
        setBrandId,
        clientIsComeState,
        clientIsNotComeState,
        clientIsComeData,
        clientIsNotComeData,
        setClientIsNotComeState,
        setClientIsNotComeData,
        setClientIsComeState,
        setClientIsComeData,
        setSelectBooking,
        setBookingId,
        setBookingType,
        bookingInfo,
        setBookingInfo,
        selectBrand,
        bookingType,
        bookingId,
        selectBooking,
        secureParams
    } = React.useContext(AppContext);
    const navigation = useNavigate();
    let {bookingCode} = useParams();

    const partnerId = partnerIdParams;

    // useEffect(() => {
    //   // В момент открытия страницы
    //   // Запросим список брендов у партнёра
    //   const brandsData = getBrandsForPartnerFromServer(partnerId)
    //     .then((data) => data.objects)
    //     .then((brands) => setBrands(brands));
    //   console.log(brandsData);
    // }, [partnerId]);

    useEffect(() => {
        // В момент открытия страницы
        // Запросим информацию о брони
        getBookingDataFromServer(bookingCode, secureParams).then((booking) => {
            // console.log("data", data);
            if (!booking) {
                // Если не пришёл объект брони, то считаем, что доступ запрещён
                setIsLoading(false);
                setCheckBrand(false)
                return
            }

            const brandUrl = booking.address.brand;
            const brand_id = brandUrl.replace("/api/autorpp/brand/", "").replace("/", "");
            setBrandId(brand_id);
            setSelectBooking({...booking, booking_type: "booking"});
            setBooking({...booking, booking_type: "booking"});
            setIsLoading(false);
        });
    }, [bookingCode]);

    React.useEffect(() => {
        // В момент открытия страницы
        // Проверим, есть ли у данного партнёра указанный бренд

        if (Number(brandId)) {
            checkBrandAccess(partnerIdParams, brandId, secureParams)
                .then(res => setCheckBrand(res))
        }
    }, [partnerIdParams, brandId]);

    // React.useEffect(()=>{
    //   console.log('checkBrand', checkBrand)
    // }, [checkBrand])

    return (
        <>
            {isLoading ? (
                    <Loader/>
                )
                : checkBrand == false ? <AccessDenied/>
                    : (
                        <>
                            {booking && clientIsNotComeState ? (
                                    // Экран "Клиент не пришёл"
                                    <ClientIsNotCome
                                        bookingId={bookingId}
                                        clientIsNotComeState={clientIsNotComeState}
                                        setClientIsNotComeState={setClientIsNotComeState}
                                        clientIsNotComeData={clientIsNotComeData}
                                        bookingType={bookingType}
                                        selectBooking={selectBooking}
                                    />
                                )
                                : booking && clientIsComeState ? (
                                        // Экран "Клиент пришёл"
                                        <ClientIsCome
                                            bookingType={bookingType}
                                            bookingId={bookingId}
                                            clientIsComeState={clientIsComeState}
                                            setClientIsComeState={setClientIsComeState}
                                            bookingInfo={bookingInfo}
                                            clientIsComeData={clientIsComeData}
                                        />
                                    )
                                    : checkBrand && booking ?
                                        <>
                                            <Container
                                                maxWidth="sm"
                                                style={{ marginTop: "1rem", marginBottom: "1rem" }}
                                            >
                                            {brandId && (
                                                <Link
                                                    to={`/booking/${brandId}#code-${booking.code}`}
                                                    style={{color: "initial", textDecoration: "none"}}
                                                    // key={index}
                                                >
                                                    <Button>Все брони</Button>
                                                </Link>
                                            )}
                                            {booking.booking_external
                                                ? <BookingWBookingExternalCard booking={booking}/>
                                                : <BookingCard booking={booking}/>}
                                            </Container>
                                        </>
                                        : (
                                            <></>
                                        )
                            }
                        </>
                    )}
        </>
    );
}
