import React from "react";
import Popup from "../Popup";
import {DatePicker, DatePickerLoader, DatePickerSuccess, DatePickerError} from './DatePickerComponents'

const DatePickerPopup = ({datePickerData, datePickerDataUtils}) => {
    return <Popup isShow={datePickerData.isShow}>
        <div style={{
            display: "flex",
            justifyContent: "center",
            flexDirection: "column",
            alignItems: "center",
            height: "100%",
            width: "100%",
        }}>
            {datePickerData.currentIndex === 0 &&
                <DatePicker datePickerDataUtils={datePickerDataUtils}/>
            }
            {datePickerData.currentIndex === 1 && <DatePickerLoader/>}
            {datePickerData.currentIndex === 2 && <DatePickerSuccess datePickerDataUtils={datePickerDataUtils}/>}
            {datePickerData.currentIndex === 3 && <DatePickerError datePickerDataUtils={datePickerDataUtils}/>}
        </div>
    </Popup>
}
export default DatePickerPopup