import * as React from "react";
import axios from "axios";
import {
  Alert,
  Button,
  Checkbox,
  FormControlLabel,
  FormGroup,
  Snackbar,
  TextField,
  Typography,
} from "@mui/material";
import { Container, Stack } from "@mui/system";
import CloseIcon from "@mui/icons-material/Close";
import AppContext from "./context";

import Loader from "./components/Loader";

import { baseURL } from "./ConfigApp";
import dayjs from "dayjs";
import { useNavigate } from "react-router-dom";

axios.defaults.baseURL = baseURL;

export default function ClientIsNotCome({
  clientIsNotComeData,
  clientIsNotComeState,
  setClientIsNotComeState,
  bookingsDrawerInfo,
}) {
  const [
    isUsePartPrepaymentAsCompensation,
    setIsUsePartPrepaymentAsCompensation,
  ] = React.useState(false);
  const [isLoading, setIsLoading] = React.useState(true);
  const [comment, setComment] = React.useState("");

  const {
    setSelectBooking,
    brandId,
    selectBrand,
    selectBooking,
    bookingInfo,
    bookingType,
    bookingId,
    allBookingsGroupSort,
    setAllBookingsGroupSort,
    secureParams,
  } = React.useContext(AppContext);
  // console.log("selectBooking", selectBooking);

  // React.useEffect(()=>{
  //   console.log('selectBooking', selectBooking)
  // },[selectBooking])

  function onTextFieldHandleChange(event, newText, setNewText) {
    setNewText(event.target.value);
  }

  const [snackbar, setSnackbar] = React.useState(null);

  const handleCloseSnackbar = () => setSnackbar(null);

  const handleProcessRowUpdateError = React.useCallback((error) => {
    setSnackbar({ children: error.message, severity: "error" });
  }, []);
  const navigate = useNavigate();
  // console.log("bookingsDrawerInfo", bookingsDrawerInfo);
  async function postClientIsNoteComeResponse(postResponseData) {

    if (postResponseData.bookingType === "booking") {
      await axios
        .post(`${baseURL}/visitor_not_come/?${secureParams}`, {
          brand: `/brand/${brandId}/`,
          booking: `/booking/${postResponseData.bookingId}/`,
          comment: postResponseData.comment,
          is_use_part_prepayment_as_compensation:
            postResponseData.is_use_part_prepayment_as_compensation,
          source_action: 'PARTNER_LK',
          who_action: 'PARTNER',
        })
        .then(function (response) {
          console.log(response);
          setSelectBooking({ ...selectBooking, visitor_not_come_bool: true });
          setAllBookingsGroupSort(
            allBookingsGroupSort.map((day) => {
              return [
                day[0],
                day[1].map((booking) => {
                  if (booking.link_code === selectBooking.link_code) {
                    return { ...booking, visitor_not_come_bool: true };
                  } else return booking;
                }),
              ];
            })
          );
          navigate(`/booking/${brandId}#code-${selectBooking.code}`);
          setClientIsNotComeState(false);
          setSnackbar({
            children: "Данные успешно изменены",
            severity: "success",
          });
        })
        .catch(function (error) {
          console.log(error);
          handleProcessRowUpdateError(new Error(error));
          // Если ошибка, то показать ошибку и предложить нажать ещё раз
        });
    } else if (postResponseData.bookingType === "booking_external") {
      await axios
        .post(`${baseURL}/visitor_not_come/?${secureParams}`, {
          brand: `/brand/${brandId}/`,
          booking_external: `/booking_external/${postResponseData.bookingId}/`,
          comment: postResponseData.comment,
          is_use_part_prepayment_as_compensation:
            postResponseData.is_use_part_prepayment_as_compensation,
          source_action: 'PARTNER_LK',
          who_action: 'PARTNER',
        })
        .then(function (response) {
          console.log(response);
          setSelectBooking({ ...selectBooking, visitor_not_come_bool: true });
          setAllBookingsGroupSort(
            allBookingsGroupSort.map((day) => {
              return [
                day[0],
                day[1].map((booking) => {
                  if (booking.link_code === selectBooking.link_code) {
                    return { ...booking, visitor_not_come_bool: true };
                  } else return booking;
                }),
              ];
            })
          );
          navigate(`/booking/${brandId}#ecode-${selectBooking.external_code}`);
          setClientIsNotComeState(false);
          setSnackbar({
            children: "Данные успешно изменены",
            severity: "success",
          });
        })
        .catch(function (error) {
          console.log(error);
          handleProcessRowUpdateError(new Error(error));
          // Если ошибка, то показать ошибку и предложить нажать ещё раз
        });
    }
  }

  React.useEffect(() => {
    setIsLoading(false);
  }, [selectBrand]);

  return (
    <>
      {isLoading ? (
        <Loader />
      ) : (
        <Container
          maxWidth="sm"
          style={{ marginTop: "1rem", marginBottom: "1rem" }}
        >
          <Stack spacing={4} sx={{ marginTop: "1.5rem" }}>
            <Stack spacing={2}>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  marginBottom: "1rem",
                }}
              >
                <Stack
                  style={{
                    display: "block",
                    margin: "0 auto",
                    textAlign: "center",
                    alignItems: "center",
                  }}
                >
                  <Typography
                    sx={{
                      textAlign: "center",
                      fontWeight: 600,
                    }}
                    variant="h4"
                  >
                    Клиент не пришёл
                  </Typography>
                  <Typography
                    sx={{
                      textAlign: "center",
                      fontWeight: 600,
                    }}
                    variant="body1"
                  >
                    Не воспользовался услугой
                  </Typography>
                </Stack>
                <CloseIcon
                  fontSize="large"
                  sx={{ cursor: "pointer" }}
                  onClick={() => setClientIsNotComeState(!clientIsNotComeState)}
                />
              </div>
              <Stack spacing={1}>
                <Typography variant="subtitle2">
                  Бронирование: №
                  {selectBooking.code
                    ? selectBooking.code
                    : selectBooking.external_code}
                </Typography>
                <Stack>
                  <Typography variant="body2">
                    Дата записи:{" "}
                    {dayjs(selectBooking.booking_date_tz).format(
                      "DD.MM.YYYY HH:mm"
                    )}
                  </Typography>
                  <Typography variant="body2">
                    {`Клиент: ${selectBooking.visitor_phone}${
                      selectBooking.visitor_name
                        ? ` ${selectBooking.visitor_name}.`
                        : "."
                    }`}
                  </Typography>
                </Stack>
              </Stack>
              <Stack>
                <TextField
                  id="outlined-search"
                  type="search"
                  label="Комментарий"
                  value={comment}
                  onChange={(e) =>
                    onTextFieldHandleChange(e, comment, setComment)
                  }
                  multiline
                ></TextField>
              </Stack>
            </Stack>
            {selectBrand.partner_settings?.isCompensationCustomerNotCome ===
              true && (
              <Stack spacing={6}>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                  }}
                >
                  <Typography
                    style={{
                      display: "block",
                      margin: "0 auto",
                      textAlign: "center",
                      alignItems: "center",
                    }}
                    sx={{
                      textAlign: "center",
                      fontWeight: 600,
                      marginBottom: "2rem",
                    }}
                    variant="h5"
                  >
                    Что сделать?
                  </Typography>
                </div>
                <Stack spacing={1}>
                  <FormGroup>
                    <FormControlLabel
                      control={
                        <Checkbox
                          checked={isUsePartPrepaymentAsCompensation}
                          onChange={(e) => {
                            setIsUsePartPrepaymentAsCompensation(
                              e.target.checked
                            );
                          }}
                        />
                      }
                      label="Использовать часть предоплаты в качестве компенсации"
                    />
                  </FormGroup>
                  <Typography sx={{ paddingLeft: "2rem" }} variant="subtitle2">
                    Предоплата {Number(bookingsDrawerInfo?.pre_pay_amount)} руб
                  </Typography>
                  <Typography sx={{ paddingLeft: "2rem" }} variant="subtitle">
                    По текущей брони клиент более не сможет записаться. Для
                    повторной записи снова потребуется предоплата
                  </Typography>
                </Stack>
              </Stack>
            )}
          </Stack>
          <Button
            sx={{
              display: "block",
              marginTop: "1rem",
              marginLeft: "auto",
            }}
            variant="contained"
            size="large"
            onClick={async () => {
              await postClientIsNoteComeResponse({
                ...bookingInfo,
                bookingId: bookingId,
                bookingType: bookingType,
                comment: comment,
                is_use_part_prepayment_as_compensation:
                  isUsePartPrepaymentAsCompensation,
              });
            }}
          >
            Сохранить
          </Button>
          {!!snackbar && (
            <Snackbar
              open
              anchorOrigin={{ vertical: "bottom", horizontal: "center" }}
              onClose={handleCloseSnackbar}
              autoHideDuration={6000}
            >
              <Alert {...snackbar} onClose={handleCloseSnackbar} />
            </Snackbar>
          )}
        </Container>
      )}
    </>
  );
}
