import React from "react";
import AppContext from "../../../context";
import dayjs from "dayjs";
import Wheel from "../../Wheel";
import {Button} from "@mui/material";
import {popupUtils} from "../../Popup";

const DataPicker = ({datePickerDataUtils}) => {
    const {
        selectBooking,
        onDateConfirmation
    } = React.useContext(AppContext);

    const [currentDay, setCurrentDay] = React.useState("")
    const [currentHour, setCurrentHour] = React.useState("")
    const [currentMinute, setCurrentMinute] = React.useState("")


    const dateTimeFormated = `${currentDay} ${currentHour}:${currentMinute}:00`

    function formatDate(_relative, absolute) {
        return dayjs(new Date()).subtract(absolute, 'day').format("dd D MMMM")
    }

    const calculateCurrentDay = (abs) => {
        const day = dayjs(new Date()).subtract(abs, 'day').format("DD.MM.YYYY")
        setCurrentDay(day)
    }
    const numberToTimeView = (value = 0) => {
        if (value >= 0) {
            if (value > 9) return value
            return "0" + value
        }
    }
    const calculateCurrentHour = (abs) => {
        let curentValue = abs
        const maxRollValue = 24

        if (abs > 0) {
            if (abs > (maxRollValue - 1)) {
                curentValue = abs - (maxRollValue * Math.trunc(abs / maxRollValue))
            }
        } else {
            if (abs < 0) {
                curentValue = maxRollValue + abs
                if (abs < -maxRollValue) {
                    curentValue = ((maxRollValue * Math.trunc(abs / maxRollValue)) - (maxRollValue + abs)) * -1
                }
            }
        }
        setCurrentHour(numberToTimeView(curentValue))
    }
    const calculateCurrentMinute = (abs) => {
        let curentValue = abs

        const maxRollValue = 60

        if (abs > 0) {
            if (abs > (maxRollValue - 1)) {
                curentValue = abs - (maxRollValue * Math.trunc(abs / maxRollValue))
            }
        } else {
            if (abs < 0) {
                curentValue = maxRollValue + abs
                if (abs < -maxRollValue) {
                    curentValue = ((maxRollValue * Math.trunc(abs / maxRollValue)) - (maxRollValue + abs)) * -1
                }
            }
        }
        setCurrentMinute(numberToTimeView(curentValue))
    }

    return (<div style={{
        maxWidth: "24rem",
        width: "100%",
    }}>
        <div style={{
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            alignItems: "center",
            background: "#fff",
            borderRadius: "0.5rem",
            margin: "1rem",
            overflow: "auto"
        }}>
            <div style={{
                height: "240px",
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
            }}>
                <div style={{width: 160, height: 180, textAlign: "center"}}>
                    <p style={{marginBottom:".25rem"}}>День</p>
                    <Wheel
                        loop
                        length={24}
                        width={160}
                        styles={{background: "#000"}}
                        perspective="right"
                        setValue={formatDate}
                        onUpdateValue={calculateCurrentDay}
                    />
                </div>
                <div style={{width: 60, height: 180, textAlign: "center"}}>
                    <p style={{marginBottom:".25rem"}}>Час</p>
                    <Wheel loop length={24} width={23} onUpdateValue={calculateCurrentHour}/>
                </div>
                <div style={{width: 60, height: 180, textAlign: "center"}}>
                    <p style={{marginBottom:".25rem"}}>Минута</p>
                    <Wheel loop length={60} width={23} perspective="left"
                           onUpdateValue={calculateCurrentMinute}/>
                </div>
            </div>
            <div style={{
                display: "flex",
                justifyContent: "center",
                background: "#fff",
                margin: "0 1rem 2rem"
            }}>
                <Button
                    sx={{width: "100%"}}
                    variant="outlined"
                    color="error"
                    onClick={() => {
                        popupUtils.onClose()
                        datePickerDataUtils.onClose()
                    }}
                >
                    Отмена
                </Button>
                <Button
                    sx={{width: "100%", marginLeft: "1rem"}}
                    variant="outlined"
                    color="success"
                    onClick={async () => {
                        await onDateConfirmation({
                            booking_id: selectBooking.id,
                            booking_datetime: dateTimeFormated
                        })
                    }}
                >
                    Подтвердить
                </Button></div>
        </div>
    </div>)

}

export default DataPicker