// список брендов конкретного партнера

// Страница запрашивает список брендов конкретного партнера
//  Если найден 1 бренд, то переадресуем на страницу/компонент <AccountOperations/>
//      Если найдено больше 1-го бренда показываем компонент со списком брендов конкретного партнера
//          При клике на любой бренд переадресуем на страницу/компонент <AccountOperations/>
//  Иначе говорим "Брендов не найдено..."

import React, {useEffect, useState} from "react";
import {Link, useNavigate} from "react-router-dom";
import axios from "axios";
import {Container, Stack} from "@mui/system";
import Loader from "./components/Loader";

import {baseURL} from "./ConfigApp";
import {Button, Typography} from "@mui/material";
import AppContext from "./context";
import ErrorPage from "./error-page";

axios.defaults.baseURL = baseURL;

export default function PartnerBrands({partnerIdParams}) {
    const [brands, setBrands] = useState([]);
    const [isLoading, setIsLoading] = React.useState(true);
    const [isError, setIsError] = React.useState(false);
    const navigation = useNavigate();

    const {selectBrand, setSelectBrand, secureParams} = React.useContext(AppContext);

    const getBrandsForPartnerFromServer = async (partnerId) => {
        try {
            await axios({
                url: `${baseURL}/brand/?partner_settings__id=${partnerId}${secureParams}`, //your url
                method: "GET",
                responseType: "json",
            })
                .then((response) => {
                    const data = response.data;
                    const meta = data.meta;
                    const brands = data.objects;
                    // console.log("meta", meta);
                    // console.log("brands", brands);
                    setBrands(brands);
                })
            setIsLoading(false);

        } catch (error) {
            console.log(error);
            setIsError(true)
            // Если ошибка, то показать ошибку и предложить нажать ещё раз

        }
    };

    useEffect(() => {
        // В момент открытия страницы
        // Запросим список брендов у партнёра
        getBrandsForPartnerFromServer(partnerIdParams);
    }, [partnerIdParams]);

    useEffect(() => {
        // console.log("brands_use", brands);
        // console.log("brands_use.length", brands.length);

        if (brands.length === 1) {
            const brand = brands[0];
            setSelectBrand({...brand});
            navigation("/booking/" + brand.id);
        }
    }, [brands]);

    return (
        <>
            {isError ? <ErrorPage/> :
                isLoading ? (
                    <Loader/>
                ) : brands && brands?.length > 0 ? (
                    <Container>
                        <Stack spacing={2} sx={{margin: "1rem auto"}} alignItems="center">
                            <Typography variant="h6" textAlign="center">
                                По какой компании показать бронирования?
                            </Typography>
                            {brands.map((brand, index) => {
                                return (
                                    <Link
                                        to={`/booking/${brand.id}`}
                                        style={{color: "initial", textDecoration: "none"}}
                                        key={index}
                                    >
                                        <Button>
                                            {brand.name}
                                        </Button>
                                    </Link>
                                );
                            })}
                        </Stack>
                        <Stack></Stack>
                    </Container>
                ) : (
                    <Container sx={{width: "30rem", margin: "1.5rem auto 0 0"}}>
                        <div>partnerId={partnerIdParams}</div>
                        <Typography variant="h6">У Вас нет ни одного бренда</Typography>
                    </Container>
                )
            }
        </>
    );
}
